import ScopedPageContent from '../components/ScopedPageContent';

const pageCss = ":root{\n    --bg:           #F8F9FA;\n    --bg-alt:       #FAFAF8;\n    --bg-soft:      #F1F2F4;\n    --bg-dark:      #0E1116;\n    --bg-dark-2:    #161A22;\n    --heading:      #2D3748;\n    --body:         #4A5568;\n    --muted:        #718096;\n    --accent-soft:  #8FBC8F;\n    --line:         #B38B6D;\n    --line-soft:    rgba(179, 139, 109, .28);\n    --line-faint:   rgba(45, 55, 72, .08);\n    --cta:          #576DB5;\n    --cta-hover:    #46599C;\n    --link:         #1E3A8A;\n    --warm:         #E5A674;\n    --font: 'Plus Jakarta Sans', system-ui, -apple-system, Segoe UI, sans-serif;\n    --max: 1320px;\n    --gutter: 24px;\n    --pad: clamp(20px, 4vw, 48px);\n  }\n\n  *{ box-sizing:border-box; }\n  html,body{ margin:0; padding:0; }\n  body{\n    background:var(--bg);\n    color:var(--body);\n    font-family:var(--font);\n    font-size:16px; line-height:1.6;\n    -webkit-font-smoothing:antialiased;\n    text-rendering:optimizeLegibility;\n    overflow-x:hidden;\n  }\n  a{ color:inherit; text-decoration:none; }\n  button{ font-family:inherit; cursor:pointer; border:0; background:transparent; }\n  img{ max-width:100%; display:block; }\n\n  .shell{\n    position:relative;\n    background:\n      radial-gradient(900px 520px at 88% 12%, rgba(143,188,143,.12), transparent 65%),\n      radial-gradient(720px 480px at 12% 90%, rgba(179,139,109,.08), transparent 70%),\n      radial-gradient(600px 400px at 50% 50%, rgba(87,109,181,.04), transparent 70%),\n      var(--bg);\n  }\n\n  .container{\n    max-width:var(--max);\n    margin:0 auto;\n    padding-left:var(--pad);\n    padding-right:var(--pad);\n    position:relative;\n  }\n\n  /* ============ NAV (matched to existing) ============ */\n  .nav-wrap{\n    position:sticky; top:0; z-index:50;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    background: rgba(248, 249, 250, .72);\n    border-bottom: 1px solid var(--line-soft);\n  }\n  .nav{\n    display:grid; grid-template-columns: auto 1fr auto;\n    align-items:center; height:78px; gap:32px;\n  }\n  .logo{ display:flex; align-items:center; height:40px; font-weight:800; font-size:18px; color:var(--heading); letter-spacing:-.01em; }\n  .logo-mark{\n    width:34px; height:34px; border-radius:9px;\n    background: linear-gradient(135deg, var(--cta) 0%, #6E84C8 100%);\n    display:grid; place-items:center; margin-right:10px;\n    box-shadow: 0 6px 16px -8px rgba(87,109,181,.5);\n  }\n  .logo-mark svg{ color:#fff; }\n\n  .menu{ display:flex; justify-content:center; gap:6px; }\n  .menu a, .menu button.menu-link{\n    position:relative;\n    display:inline-flex; align-items:center; gap:6px;\n    padding:10px 14px;\n    font-size:14.5px; font-weight:500;\n    color:var(--body); border-radius:8px;\n    transition: color .2s ease, background .2s ease;\n  }\n  .menu a:hover, .menu button.menu-link:hover{ color:var(--heading); background: rgba(179,139,109,.06); }\n  .menu a::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(0); transform-origin:left;\n    transition: transform .25s ease;\n  }\n  .menu a:hover::after{ transform:scaleX(1); }\n  .menu .menu-link.active{ color:var(--heading); background: rgba(179,139,109,.08); }\n  .menu .menu-link.active::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(1);\n  }\n  .menu .chev{ width:12px; height:12px; color:var(--muted); }\n\n  .nav-right{ display:flex; align-items:center; gap:8px; }\n  .lang{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 9px 12px;\n    font-size:13.5px; font-weight:600;\n    color:var(--body);\n    border:1px solid var(--line-soft);\n    border-radius: 999px;\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .lang:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n  .lang .globe{ color:var(--line); }\n  .lang .chev{ color:var(--muted); }\n  .icon-btn{\n    width:40px; height:40px;\n    display:grid; place-items:center;\n    border-radius:50%;\n    border:1px solid var(--line-soft);\n    color:var(--body);\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .icon-btn:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n\n  /* ============ BUTTONS ============ */\n  .btn{\n    display:inline-flex; align-items:center; gap:8px;\n    padding:12px 20px;\n    border-radius:10px;\n    font-size:14.5px; font-weight:600;\n    letter-spacing:-0.005em;\n    transition: transform .15s ease, box-shadow .2s ease, background .2s ease;\n    border: 1px solid transparent;\n  }\n  .btn-primary{\n    background:var(--cta); color:#fff;\n    box-shadow: 0 1px 0 rgba(255,255,255,.25) inset, 0 8px 22px -8px rgba(87,109,181,.55);\n  }\n  .btn-primary:hover{ background:var(--cta-hover); transform:translateY(-1px); }\n  .btn-primary svg{ transition: transform .2s ease; }\n  .btn-primary:hover svg{ transform: translateX(2px); }\n  .btn-ghost{\n    background:#fff; color:var(--heading);\n    border:1px solid var(--line-soft);\n  }\n  .btn-ghost:hover{ border-color:var(--line); transform:translateY(-1px); }\n  .btn-hero{ padding:16px 26px; font-size:15px; }\n  .link-secondary{\n    display:inline-flex; align-items:center; gap:8px;\n    color: var(--link);\n    font-weight:600; font-size:14.5px;\n    padding: 6px 2px;\n    border-bottom:1px solid transparent;\n    transition: border-color .2s, gap .2s;\n  }\n  .link-secondary:hover{ border-color: var(--link); gap:12px; }\n  .link-secondary svg{ transition: transform .2s; }\n  .link-secondary:hover svg{ transform: translateX(2px); }\n\n  /* ============ EYEBROW + REVEAL ============ */\n  .eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    padding:8px 16px 8px 12px;\n    border:1px solid var(--line-soft);\n    border-radius:999px;\n    background: rgba(255,255,255,.7);\n    backdrop-filter: blur(8px);\n    color:var(--heading);\n    font-size:12.5px; font-weight:600;\n    letter-spacing:.02em;\n    margin-bottom:28px;\n  }\n  .eyebrow .pulse{\n    position:relative;\n    width:8px; height:8px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n  .eyebrow .pulse::before{\n    content:\"\"; position:absolute; inset:-6px; border-radius:50%;\n    border:1.5px solid var(--accent-soft); opacity:.7;\n    animation: pulse 2.2s ease-out infinite;\n  }\n  @keyframes pulse{\n    0%{ transform:scale(.6); opacity:.8; }\n    100%{ transform:scale(1.4); opacity:0; }\n  }\n\n  .section-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    color:var(--muted);\n    font-size:11px; font-weight:700;\n    letter-spacing:.24em; text-transform:uppercase;\n    margin-bottom:18px;\n  }\n  .section-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background:var(--line);\n  }\n\n  .reveal{ opacity:0; transform: translateY(14px); animation: rise .9s cubic-bezier(.2,.7,.2,1) forwards; }\n  .reveal.d1{ animation-delay:.05s; }\n  .reveal.d2{ animation-delay:.15s; }\n  .reveal.d3{ animation-delay:.25s; }\n  .reveal.d4{ animation-delay:.35s; }\n  .reveal.d5{ animation-delay:.45s; }\n  @keyframes rise{ to{ opacity:1; transform: translateY(0); } }\n\n  /* ============ HERO (Inspired by SS5) ============ */\n  .hero{\n    position:relative;\n    padding-top: clamp(56px, 8vw, 96px);\n    padding-bottom: clamp(72px, 10vw, 120px);\n  }\n  .hero-grid{\n    display:grid;\n    grid-template-columns: 1.05fr 1fr;\n    gap: clamp(32px, 5vw, 72px);\n    align-items:center;\n  }\n  h1.title{\n    font-size: clamp(38px, 5vw, 68px);\n    line-height: 1.04;\n    letter-spacing: -0.028em;\n    color:var(--heading);\n    font-weight:700;\n    margin: 0 0 24px;\n    text-wrap: balance;\n  }\n  h1 .accent{ position:relative; color:var(--heading); white-space: nowrap; display: inline-block; }\n  h1 .accent::before{\n    content:\"\";\n    position:absolute;\n    left:-2px; right:-2px; bottom: 0.05em;\n    height: 14px;\n    background: linear-gradient(90deg, rgba(179,139,109,.32), rgba(143,188,143,.30));\n    z-index:-1;\n    border-radius:3px;\n    transform: skewX(-6deg);\n  }\n  .lede{\n    font-size: clamp(16px, 1.18vw, 18px);\n    line-height: 1.65;\n    color: var(--body);\n    max-width: 50ch;\n    margin: 0 0 36px;\n  }\n  .cta-row{\n    display:flex; align-items:center; gap:16px;\n    flex-wrap:wrap;\n    margin-bottom: 40px;\n  }\n\n  .trust{\n    display:flex; align-items:center; gap:18px;\n    flex-wrap:wrap;\n  }\n  .trust-label{\n    font-size:12px; font-weight:700;\n    color:var(--heading);\n    letter-spacing:.01em;\n  }\n  .trust-logos{\n    display:flex; align-items:center; gap:22px;\n    color:var(--muted); font-weight:700; font-size:14px;\n    letter-spacing:-.01em;\n  }\n  .trust-logos span{ opacity:.75; transition: opacity .2s; }\n  .trust-logos span:hover{ opacity:1; }\n\n  /* Hero Visual — floating glass cards (SS5 style) */\n  .hero-visual{\n    position:relative;\n    height: 540px;\n    perspective: 1400px;\n  }\n  .h-blob{\n    position:absolute;\n    inset: 8% 0 0 12%;\n    width: 78%; height: 80%;\n    background:\n      radial-gradient(60% 60% at 50% 40%, rgba(143,188,143,.22), transparent 70%),\n      radial-gradient(70% 70% at 60% 60%, rgba(179,139,109,.18), transparent 70%);\n    filter: blur(10px);\n    border-radius: 50% 50% 50% 50% / 60% 60% 40% 40%;\n    z-index:0;\n  }\n  .h-card{\n    position:absolute;\n    background: rgba(255,255,255,.72);\n    backdrop-filter: blur(16px) saturate(140%);\n    -webkit-backdrop-filter: blur(16px) saturate(140%);\n    border: 1px solid rgba(255,255,255,.85);\n    border-radius: 18px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.9) inset,\n      0 18px 40px -18px rgba(45,55,72,.22),\n      0 6px 20px -10px rgba(45,55,72,.10);\n    padding: 14px 16px;\n    z-index: 2;\n  }\n\n  /* main workflow card — center */\n  .h-main{\n    top: 14%; left: 8%;\n    width: 64%;\n    padding: 18px;\n    transform: rotate(-2deg);\n    background: rgba(248,249,250,.85);\n    border-radius: 22px;\n  }\n  .h-main-head{\n    display:flex; align-items:center; justify-content:space-between;\n    margin-bottom:16px;\n  }\n  .h-main-title{\n    display:flex; align-items:center; gap:10px;\n    font-size:13px; font-weight:700; color:var(--heading);\n  }\n  .h-main-title .dot{\n    width:8px; height:8px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.18);\n  }\n  .h-main-tag{\n    font-size:11px; font-weight:700; color:var(--cta);\n    background: rgba(87,109,181,.10);\n    padding:4px 9px; border-radius:6px;\n    letter-spacing:.04em;\n  }\n  .h-flow{\n    display:grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap:8px;\n    align-items:center;\n    position:relative;\n  }\n  .h-node{\n    background:#fff;\n    border:1px solid var(--line-soft);\n    border-radius:10px;\n    padding:10px 8px;\n    text-align:center;\n    font-size:11px; font-weight:600; color:var(--heading);\n    box-shadow: 0 4px 12px -8px rgba(45,55,72,.18);\n    position:relative; z-index:2;\n  }\n  .h-node svg{ display:block; margin: 0 auto 4px; color:var(--cta); }\n  .h-node:nth-child(2) svg{ color:var(--line); }\n  .h-node:nth-child(3) svg{ color:var(--accent-soft); }\n  .h-node:nth-child(4) svg{ color:var(--warm); }\n  .h-flow::before{\n    content:\"\"; position:absolute;\n    top:50%; left:8%; right:8%;\n    height:1px;\n    background: linear-gradient(90deg, transparent, var(--line-soft) 20%, var(--line-soft) 80%, transparent);\n    z-index:1;\n  }\n  .h-main-foot{\n    margin-top:14px;\n    display:flex; align-items:center; justify-content:space-between;\n    padding-top:12px; border-top: 1px dashed var(--line-soft);\n  }\n  .h-foot-stat{ display:flex; align-items:baseline; gap:6px; }\n  .h-foot-stat strong{\n    font-size:18px; font-weight:800; color:var(--heading); letter-spacing:-.02em;\n  }\n  .h-foot-stat span{ font-size:11px; color:var(--muted); font-weight:600; }\n  .h-foot-cta{\n    font-size:11px; font-weight:700; color:var(--cta);\n    display:inline-flex; align-items:center; gap:4px;\n  }\n\n  /* notification card — top right */\n  .h-notif{\n    top: 4%; right: 0;\n    width: 50%;\n    transform: rotate(3deg);\n    animation: drift 9s ease-in-out infinite;\n  }\n  .h-notif-head{\n    display:flex; align-items:center; gap:10px;\n    margin-bottom:8px;\n  }\n  .h-notif-icon{\n    width:28px; height:28px; border-radius:8px;\n    background: rgba(143,188,143,.18);\n    display:grid; place-items:center; color: #4a8c4a;\n    flex-shrink:0;\n  }\n  .h-notif-title{\n    font-size:12.5px; font-weight:700; color:var(--heading); line-height:1.3;\n  }\n  .h-notif-time{ font-size:10.5px; color:var(--muted); font-weight:600; }\n  .h-notif p{\n    margin:0; font-size:11.5px; line-height:1.5; color:var(--body);\n  }\n\n  /* integrations card — bottom right */\n  .h-integ{\n    bottom: 6%; right: 4%;\n    width: 56%;\n    padding: 14px 16px;\n    transform: rotate(-1.5deg);\n    animation: drift 10s ease-in-out infinite reverse;\n    animation-delay: -2s;\n  }\n  .h-integ-title{\n    font-size:11.5px; font-weight:700; color:var(--heading);\n    margin-bottom:10px; letter-spacing:.02em;\n  }\n  .h-integ-row{ display:flex; align-items:center; gap:6px; }\n  .h-int{\n    width:34px; height:34px; border-radius:9px;\n    border:1px solid var(--line-soft);\n    background:#fff;\n    display:grid; place-items:center;\n    font-size:10px; font-weight:800;\n    color:var(--heading);\n    box-shadow: 0 4px 10px -6px rgba(45,55,72,.12);\n    flex-shrink:0;\n  }\n  .h-int.gs{ color:#0F9D58; }\n  .h-int.tw{ color:#F22F46; }\n  .h-int.gp{ color:#10A37F; }\n  .h-int.sl{ color:#4A154B; }\n  .h-int.fb{ color:#1877F2; }\n  .h-integ-row .more{\n    color:var(--muted); font-size:11px; font-weight:700;\n    margin-left:4px;\n  }\n\n  /* small floating chip — bottom left */\n  .h-chip{\n    bottom: 22%; left: -2%;\n    background: rgba(45,55,72,.92);\n    color: #fff;\n    border:1px solid rgba(255,255,255,.12);\n    padding: 10px 14px;\n    border-radius: 999px;\n    font-size: 12px; font-weight: 600;\n    display:flex; align-items:center; gap:8px;\n    transform: rotate(-3deg);\n    animation: drift 11s ease-in-out infinite;\n    animation-delay: -4s;\n    box-shadow: 0 18px 40px -16px rgba(45,55,72,.5);\n  }\n  .h-chip .c-dot{\n    width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 3px rgba(143,188,143,.22);\n  }\n\n  @keyframes drift{\n    0%,100%{ transform: translateY(0) rotate(var(--rot, 0deg)); }\n    50%{ transform: translateY(-8px) rotate(var(--rot, 0deg)); }\n  }\n  .h-notif{ --rot: 3deg; }\n  .h-integ{ --rot: -1.5deg; }\n  .h-chip{ --rot: -3deg; }\n\n  /* ============ SECTION 2 — What is Healthcare Automation (SS4 style) ============ */\n  .what-is{\n    position:relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    border-top: 1px solid var(--line-faint);\n    background: var(--bg-alt);\n  }\n  .what-grid{\n    display:grid;\n    grid-template-columns: 0.85fr 1.15fr;\n    gap: clamp(40px, 6vw, 80px);\n    align-items: start;\n  }\n  h2.section-title{\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color:var(--heading);\n    font-weight:700;\n    margin: 0 0 22px;\n    max-width: 16ch;\n    text-wrap: balance;\n  }\n  .what-text{\n    font-size: 16px;\n    line-height: 1.7;\n    color: var(--body);\n    margin: 0 0 28px;\n    max-width: 42ch;\n  }\n  .more-info{\n    display:inline-flex; align-items:center; gap:14px;\n    text-decoration:none;\n    color: var(--heading); font-weight:700; font-size:15px;\n    margin-bottom: 40px;\n  }\n  .more-info-icon{\n    width:48px; height:48px;\n    background: var(--cta);\n    /* hexagon */\n    clip-path: polygon(25% 5%, 75% 5%, 100% 50%, 75% 95%, 25% 95%, 0% 50%);\n    display:grid; place-items:center;\n    color:#fff;\n    transition: transform .25s ease;\n  }\n  .more-info:hover .more-info-icon{ transform: rotate(60deg) scale(1.05); }\n\n  /* Right collage grid (SS4 style) */\n  .what-collage{\n    display:grid;\n    grid-template-columns: 1fr 1.4fr 1fr;\n    grid-template-rows: 0.9fr 1.2fr 0.9fr;\n    gap: 12px;\n    aspect-ratio: 1.4;\n    grid-template-areas:\n      \"a b b\"\n      \"c d e\"\n      \"f g g\";\n  }\n  .col-tile{\n    border-radius: 14px;\n    background: var(--bg-soft);\n    border: 1px solid var(--line-soft);\n    display:flex; align-items:center; justify-content:center;\n    padding: 16px;\n    position:relative;\n    overflow:hidden;\n    transition: transform .35s ease, box-shadow .35s ease;\n  }\n  .col-tile:hover{\n    transform: translateY(-3px);\n    box-shadow: 0 16px 32px -18px rgba(45,55,72,.2);\n  }\n  .col-tile.tile-a{ grid-area:a; background: linear-gradient(135deg, #fff 0%, var(--bg-soft) 100%); }\n  .col-tile.tile-b{\n    grid-area:b;\n    background: linear-gradient(135deg, rgba(143,188,143,.16), rgba(255,255,255,.6));\n  }\n  .col-tile.tile-c{ grid-area:c; }\n  .col-tile.tile-d{\n    grid-area:d;\n    background: linear-gradient(135deg, rgba(87,109,181,.10), rgba(255,255,255,.6));\n    flex-direction:column; justify-content:flex-start; align-items:flex-start;\n  }\n  .col-tile.tile-e{ grid-area:e; background: linear-gradient(135deg, #fff 0%, var(--bg-soft) 100%); }\n  .col-tile.tile-f{ grid-area:f; }\n  .col-tile.tile-g{\n    grid-area:g;\n    background: linear-gradient(135deg, rgba(179,139,109,.12), rgba(255,255,255,.6));\n  }\n  .tile-d-title{\n    font-size: 17px; font-weight:700; color:var(--heading);\n    margin-bottom:12px; letter-spacing:-.01em;\n  }\n  .tile-d-illust{\n    flex:1; width:100%;\n    display:grid; place-items:center;\n  }\n  .tile-d-foot{\n    font-size:11px; color:var(--muted); font-weight:600;\n    margin-top:10px; align-self:flex-end;\n  }\n\n  .col-icon{\n    width: 60%; max-width: 110px;\n    aspect-ratio:1;\n    display:grid; place-items:center;\n  }\n\n  /* ============ SECTION 2.5 — Solutions Library (Swiss design) ============ */\n  .solutions{\n    position: relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    background: var(--bg);\n    border-top: 1px solid var(--line-faint);\n    overflow: hidden;\n  }\n  .solutions::before{\n    content: \"\";\n    position: absolute;\n    top: -10%; right: -10%;\n    width: 50%; height: 60%;\n    background: radial-gradient(50% 50% at 50% 50%, rgba(143,188,143,.10), transparent 70%);\n    pointer-events: none;\n  }\n  .sol-head{\n    display: grid;\n    grid-template-columns: 1.2fr 1fr;\n    gap: 48px;\n    align-items: end;\n    margin-bottom: 64px;\n    position: relative;\n  }\n  .sol-head-left{ position: relative; }\n  .sol-head .section-title{ margin: 0; }\n  .sol-sub{\n    margin: 0 0 6px auto;\n    max-width: 38ch;\n    font-size: 15.5px; line-height: 1.65;\n    color: var(--body);\n    text-align: right;\n  }\n\n  /* Glass card grid */\n  .sol-grid{\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 18px;\n  }\n  .sol-card{\n    position: relative;\n    display: flex; flex-direction: column;\n    padding: 24px 22px 22px;\n    background: rgba(255,255,255,.7);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid rgba(255,255,255,.9);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.9) inset,\n      0 8px 24px -16px rgba(45,55,72,.10);\n    border-radius: 18px;\n    text-decoration: none;\n    color: var(--heading);\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), box-shadow .35s ease, background .35s ease, border-color .35s ease;\n    overflow: hidden;\n    min-height: 220px;\n    isolation: isolate;\n  }\n  .sol-card::before{\n    content: \"\";\n    position: absolute;\n    inset: 0;\n    background:\n      radial-gradient(120% 80% at 100% 0%, rgba(143,188,143,.20), transparent 55%),\n      radial-gradient(120% 80% at 0% 100%, rgba(87,109,181,.16), transparent 55%);\n    opacity: 0;\n    transition: opacity .35s ease;\n    pointer-events: none;\n    z-index: -1;\n  }\n  .sol-card::after{\n    content: \"\";\n    position: absolute;\n    top: 0; left: 0; right: 0; height: 2px;\n    background: linear-gradient(90deg, var(--cta), var(--accent-soft), var(--line));\n    transform: scaleX(0); transform-origin: left;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1);\n    border-radius: 2px;\n  }\n  .sol-card:hover{\n    transform: translateY(-6px);\n    background: rgba(255,255,255,.9);\n    border-color: rgba(255,255,255,1);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,1) inset,\n      0 28px 56px -28px rgba(45,55,72,.22),\n      0 12px 28px -16px rgba(87,109,181,.18);\n  }\n  .sol-card:hover::before{ opacity: 1; }\n  .sol-card:hover::after{ transform: scaleX(1); }\n\n  .sol-card-top{\n    display: flex; align-items: flex-start; justify-content: space-between;\n    margin-bottom: 22px;\n    gap: 12px;\n  }\n  .sol-icon{\n    width: 48px; height: 48px;\n    border-radius: 14px;\n    background: linear-gradient(135deg, rgba(87,109,181,.14), rgba(143,188,143,.18));\n    border: 1px solid rgba(255,255,255,.8);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.9) inset,\n      0 6px 16px -10px rgba(45,55,72,.20);\n    display: grid; place-items: center;\n    color: var(--cta);\n    flex-shrink: 0;\n    transition: transform .35s ease, background .35s ease;\n  }\n  .sol-icon svg{ width: 22px; height: 22px; }\n  .sol-card:hover .sol-icon{\n    transform: rotate(-4deg) scale(1.06);\n    background: linear-gradient(135deg, rgba(87,109,181,.22), rgba(143,188,143,.28));\n  }\n\n  /* glass arrow button */\n  .sol-arrow{\n    width: 36px; height: 36px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.55);\n    backdrop-filter: blur(10px) saturate(140%);\n    -webkit-backdrop-filter: blur(10px) saturate(140%);\n    border: 1px solid rgba(255,255,255,.9);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.9) inset,\n      0 4px 12px -6px rgba(45,55,72,.18);\n    color: var(--heading);\n    display: grid; place-items: center;\n    flex-shrink: 0;\n    transition: background .25s ease, color .25s ease, transform .25s ease, box-shadow .25s ease;\n  }\n  .sol-arrow svg{ width: 14px; height: 14px; transition: transform .3s ease; }\n  .sol-card:hover .sol-arrow{\n    background: var(--heading);\n    color: #fff;\n    border-color: var(--heading);\n    transform: translate(2px, -2px);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.1) inset,\n      0 10px 20px -8px rgba(45,55,72,.4);\n  }\n  .sol-card:hover .sol-arrow svg{ transform: rotate(-8deg); }\n\n  .sol-title{\n    font-size: 17px;\n    font-weight: 700;\n    color: var(--heading);\n    margin: 0 0 8px;\n    line-height: 1.3;\n    letter-spacing: -.01em;\n  }\n  .sol-desc{\n    font-size: 13.5px;\n    line-height: 1.55;\n    color: var(--muted);\n    margin: 0;\n  }\n\n  /* ============ SECTION 3 — Glass Banner with 3D (SS1 style) ============ */\n  .impact{\n    position:relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    background: var(--bg);\n    border-top: 1px solid var(--line-faint);\n  }\n  .impact-banner{\n    position:relative;\n    background:\n      radial-gradient(700px 400px at 15% 30%, rgba(87,109,181,.20), transparent 65%),\n      radial-gradient(600px 380px at 85% 75%, rgba(179,139,109,.18), transparent 65%),\n      linear-gradient(135deg, #0E1116 0%, #1B2030 50%, #161A22 100%);\n    border-radius: 32px;\n    overflow: hidden;\n    padding: clamp(36px, 5vw, 64px);\n    display:grid;\n    grid-template-columns: 1fr 1.4fr;\n    gap: clamp(32px, 5vw, 64px);\n    align-items: center;\n    box-shadow:\n      0 30px 80px -30px rgba(45,55,72,.4),\n      0 1px 0 rgba(255,255,255,.05) inset;\n  }\n  /* glow corners on banner */\n  .impact-banner::before{\n    content:\"\";\n    position:absolute;\n    top:-50%; right:-20%;\n    width:60%; height:120%;\n    background: radial-gradient(50% 50% at 50% 50%, rgba(143,188,143,.15), transparent 70%);\n    pointer-events:none;\n  }\n  .impact-banner::after{\n    content:\"\";\n    position:absolute;\n    bottom:-50%; left:-20%;\n    width:60%; height:120%;\n    background: radial-gradient(50% 50% at 50% 50%, rgba(229,166,116,.12), transparent 70%);\n    pointer-events:none;\n  }\n\n  /* Left side — 3D workflow visual */\n  .impact-visual{\n    position:relative;\n    aspect-ratio: 1.05;\n    perspective: 1200px;\n    z-index:1;\n  }\n  .impact-3d{\n    position:absolute; inset:0;\n    transform-style: preserve-3d;\n    transform: rotateY(-14deg) rotateX(8deg);\n    animation: tilt 10s ease-in-out infinite;\n  }\n  @keyframes tilt{\n    0%,100%{ transform: rotateY(-14deg) rotateX(8deg); }\n    50%   { transform: rotateY(-10deg) rotateX(4deg); }\n  }\n  .impact-card{\n    position:absolute;\n    background: rgba(255,255,255,.06);\n    border: 1px solid rgba(255,255,255,.14);\n    border-radius: 18px;\n    backdrop-filter: blur(20px) saturate(140%);\n    -webkit-backdrop-filter: blur(20px) saturate(140%);\n    padding: 18px;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.08) inset,\n      0 30px 60px -30px rgba(0,0,0,.6);\n  }\n  .impact-card.ic-back{\n    top: 0; left: 0; right: 0; bottom: 0;\n    transform: translateZ(-30px) translateX(-10%) translateY(8%);\n    opacity: .6;\n  }\n  .impact-card.ic-mid{\n    top: 8%; left: 6%; right: 6%; bottom: 8%;\n    transform: translateZ(0);\n  }\n  .impact-card.ic-front{\n    top: 22%; left: 18%; right: -6%; bottom: 18%;\n    transform: translateZ(40px);\n  }\n  .ic-head{\n    display:flex; align-items:center; justify-content:space-between;\n    margin-bottom: 14px;\n  }\n  .ic-dots{ display:flex; gap:5px; }\n  .ic-dots span{ width:8px; height:8px; border-radius:50%; background: rgba(255,255,255,.15); }\n  .ic-dots span:nth-child(1){ background: #FF5F56; }\n  .ic-dots span:nth-child(2){ background: #FFBD2E; }\n  .ic-dots span:nth-child(3){ background: #27C93F; }\n  .ic-tag{\n    font-size: 10px; font-weight:700;\n    color: var(--accent-soft);\n    background: rgba(143,188,143,.14);\n    padding: 3px 8px; border-radius: 6px;\n    letter-spacing: .06em; text-transform: uppercase;\n  }\n  .ic-flow{\n    display:flex; flex-direction:column; gap:10px;\n  }\n  .ic-step{\n    display:flex; align-items:center; gap:10px;\n    padding: 10px 12px;\n    background: rgba(255,255,255,.04);\n    border: 1px solid rgba(255,255,255,.08);\n    border-radius: 10px;\n    color:#fff;\n    font-size: 12px; font-weight:600;\n  }\n  .ic-step .ic-num{\n    width:22px; height:22px; border-radius:50%;\n    background: rgba(143,188,143,.18); color: var(--accent-soft);\n    display:grid; place-items:center;\n    font-size: 10.5px; font-weight:800;\n    border: 1px solid rgba(143,188,143,.3);\n    flex-shrink:0;\n  }\n  .ic-step .ic-pulse{\n    margin-left:auto;\n    width:6px; height:6px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 12px rgba(143,188,143,.7);\n  }\n\n  /* Right side — content */\n  .impact-content{ position:relative; z-index:1; color:#fff; }\n  .impact-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    color:var(--accent-soft); font-size:11px;\n    font-weight:700; letter-spacing:.24em; text-transform:uppercase;\n    margin-bottom:16px;\n  }\n  .impact-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 12px rgba(143,188,143,.6);\n  }\n  .impact-title{\n    font-size: clamp(30px, 3.6vw, 48px);\n    line-height: 1.05;\n    font-weight: 700;\n    color: #fff;\n    letter-spacing: -.02em;\n    margin: 0 0 18px;\n    text-wrap: balance;\n  }\n  .impact-lede{\n    font-size: 15.5px; line-height: 1.65;\n    color: rgba(255,255,255,.72);\n    max-width: 56ch;\n    margin: 0 0 36px;\n  }\n  .impact-stats{\n    display:grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 24px;\n  }\n  .impact-stat{\n    position:relative;\n  }\n  .impact-stat::before{\n    content:\"\";\n    position:absolute; left:-12px; top:0; bottom:0;\n    width:1px; background: rgba(255,255,255,.10);\n  }\n  .impact-stat:first-child::before{ display:none; }\n  .impact-stat .label{\n    font-size: 13px; color: rgba(255,255,255,.55);\n    font-weight: 600; margin-bottom: 6px;\n    letter-spacing: .01em;\n  }\n  .impact-stat .value{\n    font-size: clamp(34px, 4vw, 52px);\n    font-weight: 700;\n    color: var(--warm);\n    letter-spacing: -.03em;\n    line-height: 1;\n    margin-bottom: 10px;\n  }\n  .impact-stat .desc{\n    font-size: 13px;\n    color: rgba(255,255,255,.6);\n    line-height: 1.5;\n  }\n  .impact-foot{\n    margin-top: 32px;\n    display:flex; align-items:center; gap:18px;\n    flex-wrap:wrap;\n  }\n  .impact-badge{\n    font-size: 13px; font-weight: 700;\n    color: var(--warm);\n  }\n  .impact-note{\n    font-size: 12.5px;\n    color: rgba(255,255,255,.5);\n    line-height:1.5;\n  }\n\n  /* ============ SECTION 4 — N8N TEMPLATES (Slider) ============ */\n  .templates{\n    position:relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    background: var(--bg-alt);\n    border-top: 1px solid var(--line-faint);\n  }\n  .templates-head{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr;\n    gap: 60px;\n    align-items: end;\n    margin-bottom: 48px;\n  }\n  .templates-head .right{\n    text-align: right;\n    color: var(--body);\n    font-size: 15.5px;\n    line-height: 1.65;\n    max-width: 38ch;\n    margin-left: auto;\n    padding-bottom: 6px;\n  }\n  .free-pill{\n    display:inline-flex; align-items:center; gap:8px;\n    padding: 7px 14px;\n    background: rgba(143,188,143,.16);\n    color: #4a8c4a;\n    border: 1px solid rgba(143,188,143,.4);\n    border-radius: 999px;\n    font-size: 12px; font-weight: 700;\n    letter-spacing: .02em;\n    margin-bottom: 18px;\n  }\n  .free-pill .check{\n    width:14px; height:14px; border-radius:50%;\n    background: #4a8c4a; color:#fff;\n    display:grid; place-items:center;\n  }\n\n  /* Slider */\n  .slider-wrap{ position:relative; }\n  .slider-track-wrap{\n    overflow: hidden;\n    margin: 0 -16px;\n    padding: 12px 16px;\n  }\n  .slider-track{\n    display:flex;\n    gap: clamp(40px, 6vw, 96px);\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n    will-change: transform;\n  }\n  .tpl-card{\n    flex: 0 0 calc((100% - clamp(40px, 6vw, 96px)) / 2);\n    display:flex; flex-direction: column;\n    padding: 8px 4px 4px;\n    position:relative;\n  }\n  .tpl-quote{\n    width: 56px; height: 44px;\n    color: rgba(179,139,109,.22);\n    margin-bottom: 22px;\n  }\n  .tpl-quote svg{ width: 100%; height: 100%; display: block; }\n\n  .tpl-desc{\n    font-size: clamp(17px, 1.4vw, 21px);\n    line-height: 1.55;\n    color: var(--heading);\n    margin: 0 0 36px;\n    font-weight: 500;\n    letter-spacing: -.005em;\n    max-width: 52ch;\n  }\n  .tpl-tags{\n    display:flex; flex-wrap:wrap; gap:6px;\n    margin-bottom: 22px;\n  }\n  .tpl-tag{\n    font-size: 11px; font-weight: 600;\n    color: var(--muted);\n    padding: 4px 9px;\n    background: var(--bg-soft);\n    border-radius: 5px;\n    letter-spacing: .01em;\n  }\n\n  .tpl-author{\n    display:flex; align-items:center; gap: 16px;\n    padding-left: 18px;\n    border-left: 2px solid var(--line);\n    margin-bottom: 24px;\n  }\n  .tpl-icon{\n    width: 52px; height: 52px;\n    border-radius: 50%;\n    background: linear-gradient(135deg, rgba(87,109,181,.14), rgba(143,188,143,.18));\n    border: 1px solid var(--line-soft);\n    display:grid; place-items:center;\n    color: var(--cta);\n    flex-shrink: 0;\n  }\n  .tpl-author-meta{ display: flex; flex-direction: column; gap: 2px; }\n  .tpl-title{\n    font-size: 16px; font-weight: 700;\n    color: var(--heading);\n    margin: 0;\n    line-height: 1.3;\n    letter-spacing: -.005em;\n  }\n  .tpl-nodes{\n    font-size: 13px; font-weight: 500;\n    color: var(--muted);\n    letter-spacing: .005em;\n  }\n\n  .tpl-dl{\n    align-self: flex-start;\n    display:inline-flex; align-items:center;\n    gap: 10px;\n    padding: 11px 18px;\n    background: transparent;\n    color: var(--heading);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 13px; font-weight: 600;\n    transition: background .2s, color .2s, border-color .2s, transform .15s, gap .2s;\n  }\n  .tpl-dl:hover{\n    background: var(--heading); color: #fff;\n    border-color: var(--heading);\n    transform: translateY(-1px);\n    gap: 14px;\n  }\n  .tpl-dl svg{ flex-shrink: 0; transition: transform .2s; }\n\n  /* Slider controls — centered layout */\n  .slider-controls{\n    display:flex; align-items:center; justify-content:center;\n    margin-top: 56px;\n    gap: 24px;\n  }\n  .slider-progress{\n    flex: 0 1 460px;\n    height: 1px;\n    background: transparent;\n    background-image: linear-gradient(to right, var(--line-soft) 50%, transparent 50%);\n    background-size: 8px 1px;\n    background-repeat: repeat-x;\n    border-radius: 0;\n    overflow: visible;\n    position: relative;\n  }\n  .slider-fill{\n    position:absolute; left:0; top: -1px; height: 3px;\n    background: var(--heading);\n    border-radius: 3px;\n    transition: width .55s cubic-bezier(.2,.7,.2,1);\n  }\n  .slider-btns{ display: contents; }\n  .slider-btn{\n    order: 0;\n    width: 40px; height: 40px;\n    background: transparent;\n    border: 0;\n    color: var(--heading);\n    display:grid; place-items:center;\n    transition: color .2s, transform .15s, opacity .2s;\n  }\n  .slider-btn[data-prev]{ order: -1; }\n  .slider-btn[data-next]{ order: 1; }\n  .slider-btn:hover{ color: var(--cta); transform: translateX(0); }\n  .slider-btn[data-prev]:hover{ transform: translateX(-2px); }\n  .slider-btn[data-next]:hover{ transform: translateX(2px); }\n  .slider-btn:disabled{ opacity:.25; cursor:not-allowed; transform:none; }\n  .slider-btn svg{ width: 22px; height: 22px; }\n\n  .templates-foot{\n    margin-top: 56px;\n    padding: 28px 32px;\n    background: linear-gradient(135deg, rgba(143,188,143,.10), rgba(179,139,109,.08));\n    border: 1px solid var(--line-soft);\n    border-radius: 16px;\n    display:flex; align-items:center; justify-content:space-between;\n    gap: 24px;\n    flex-wrap:wrap;\n  }\n  .templates-foot p{\n    margin: 0;\n    font-size: 16px; font-weight: 600;\n    color: var(--heading);\n    letter-spacing: -.005em;\n  }\n\n  /* ============ SECTION 5 — Use Cases (SS6 style, dark) ============ */\n  .usecases{\n    position:relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    background: linear-gradient(180deg, #0E1116 0%, #14181F 100%);\n    color: #fff;\n    overflow: hidden;\n  }\n  .usecases::before{\n    content:\"\";\n    position:absolute;\n    top: 10%; left: -10%;\n    width: 50%; height: 80%;\n    background: radial-gradient(50% 50% at 50% 50%, rgba(87,109,181,.10), transparent 70%);\n    pointer-events:none;\n  }\n  .uc-head{\n    margin-bottom: 64px;\n    max-width: 760px;\n  }\n  .uc-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    color: var(--accent-soft);\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .24em; text-transform: uppercase;\n    margin-bottom: 22px;\n  }\n  .uc-eyebrow::before{\n    content:\"\"; width: 7px; height: 7px; border-radius: 50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 12px rgba(143,188,143,.5);\n  }\n  .uc-head h2{\n    font-size: clamp(34px, 4.6vw, 60px);\n    line-height: 1.04;\n    letter-spacing: -.025em;\n    color: #fff;\n    font-weight: 700;\n    margin: 0 0 18px;\n    text-wrap: balance;\n  }\n  .uc-sub{\n    font-size: 16px; line-height: 1.65;\n    color: rgba(255,255,255,.6);\n    margin: 0;\n    max-width: 56ch;\n  }\n\n  .uc-grid{\n    display:grid;\n    grid-template-columns: 1fr 1.1fr;\n    gap: clamp(40px, 6vw, 96px);\n    align-items: center;\n  }\n\n  /* LEFT — circles visual */\n  .uc-visual{\n    position: relative;\n    aspect-ratio: 1;\n    max-width: 520px;\n    margin: 0 auto;\n    width: 100%;\n  }\n  .uc-circles{\n    position: absolute;\n    inset: 0;\n  }\n  .uc-ring{\n    position: absolute;\n    border-radius: 50%;\n    border: 1px dashed rgba(255,255,255,.22);\n    pointer-events: none;\n    animation: uc-spin 30s linear infinite;\n  }\n  .uc-r1{ inset: 18% 30% 20% 14%; animation-duration: 38s; }\n  .uc-r2{ inset: 8% 12% 30% 30%; animation-duration: 46s; animation-direction: reverse; border-color: rgba(255,255,255,.18); }\n  .uc-r3{ inset: 32% 8% 8% 28%; animation-duration: 52s; border-color: rgba(143,188,143,.30); }\n  .uc-r4{ inset: 22% 22% 22% 22%; animation-duration: 70s; animation-direction: reverse; border-color: rgba(255,255,255,.10); }\n  .uc-r5{ inset: 4% 36% 38% 8%; animation-duration: 60s; border-color: rgba(255,255,255,.14); }\n  @keyframes uc-spin{\n    from{ transform: rotate(0deg); }\n    to  { transform: rotate(360deg); }\n  }\n  .uc-orb{\n    position: absolute;\n    top: 50%; left: 50%;\n    transform: translate(-50%, -50%);\n    width: 46%; aspect-ratio: 1;\n    border-radius: 50%;\n    background: #fff;\n    color: var(--heading);\n    display: flex; flex-direction: column;\n    align-items: center; justify-content: center;\n    text-align: center;\n    padding: 8%;\n    box-shadow:\n      0 30px 60px -20px rgba(0,0,0,.5),\n      0 0 0 1px rgba(255,255,255,.08),\n      0 0 80px rgba(255,255,255,.12);\n    z-index: 2;\n    transition: transform .5s cubic-bezier(.2,.7,.2,1);\n  }\n  .uc-orb-num{\n    font-size: clamp(22px, 2.6vw, 32px);\n    font-weight: 800;\n    letter-spacing: -.03em;\n    color: var(--heading);\n    margin-bottom: 6px;\n    transition: opacity .25s;\n  }\n  .uc-orb-title{\n    font-size: clamp(13px, 1.1vw, 15px);\n    font-weight: 700;\n    line-height: 1.25;\n    color: var(--heading);\n    letter-spacing: -.005em;\n    transition: opacity .25s;\n  }\n  .uc-orb.is-swap .uc-orb-num,\n  .uc-orb.is-swap .uc-orb-title{ opacity: 0; }\n\n  /* RIGHT — accordion list */\n  .uc-list{ display: flex; flex-direction: column; }\n  .uc-row{\n    width: 100%;\n    text-align: left;\n    color: #fff;\n    background: transparent;\n    border: 0;\n    border-top: 1px solid rgba(255,255,255,.10);\n    padding: 22px 0;\n    cursor: pointer;\n    font-family: var(--font);\n    transition: background .25s;\n  }\n  .uc-row:last-child{ border-bottom: 1px solid rgba(255,255,255,.10); }\n  .uc-row-head{\n    display: flex; align-items: center; justify-content: space-between;\n    gap: 16px;\n  }\n  .uc-row-title{\n    font-size: clamp(17px, 1.6vw, 21px);\n    font-weight: 700;\n    color: #fff;\n    letter-spacing: -.01em;\n    transition: color .25s;\n  }\n  .uc-row-icon{\n    width: 30px; height: 30px;\n    border-radius: 50%;\n    border: 1px solid rgba(255,255,255,.25);\n    color: rgba(255,255,255,.7);\n    display: grid; place-items: center;\n    flex-shrink: 0;\n    transition: transform .35s, border-color .25s, color .25s, background .25s;\n  }\n  .uc-row-icon svg{ width: 14px; height: 14px; }\n  .uc-row:hover .uc-row-title{ color: var(--accent-soft); }\n  .uc-row:hover .uc-row-icon{ border-color: var(--accent-soft); color: var(--accent-soft); }\n\n  .uc-row.is-open .uc-row-icon{\n    transform: rotate(45deg);\n    background: var(--accent-soft);\n    border-color: var(--accent-soft);\n    color: #14181F;\n  }\n  .uc-row.is-open .uc-row-title{ color: #fff; }\n\n  .uc-row-body{\n    overflow: hidden;\n    max-height: 0;\n    opacity: 0;\n    transition: max-height .5s cubic-bezier(.2,.7,.2,1), opacity .35s ease, margin-top .35s ease;\n  }\n  .uc-row.is-open .uc-row-body{\n    max-height: 600px;\n    opacity: 1;\n    margin-top: 18px;\n  }\n  .uc-row-tag{\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .12em;\n    color: rgba(255,255,255,.5);\n    text-transform: uppercase;\n    margin-bottom: 10px;\n  }\n  .uc-row-h{\n    font-size: 18px; font-weight: 700;\n    color: #fff;\n    margin-bottom: 12px;\n    letter-spacing: -.005em;\n  }\n  .uc-row-p{\n    font-size: 14.5px; line-height: 1.65;\n    color: rgba(255,255,255,.7);\n    margin: 0 0 16px;\n    max-width: 60ch;\n  }\n  .uc-row-list{\n    margin: 0; padding: 0; list-style: none;\n    display: grid; gap: 8px;\n  }\n  .uc-row-list li{\n    position: relative;\n    padding-left: 22px;\n    font-size: 13.5px; line-height: 1.55;\n    color: rgba(255,255,255,.75);\n  }\n  .uc-row-list li::before{\n    content: \"\";\n    position: absolute;\n    left: 0; top: 7px;\n    width: 12px; height: 12px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.18);\n    box-shadow: inset 0 0 0 1px rgba(143,188,143,.5);\n  }\n  .uc-row-list li::after{\n    content: \"\";\n    position: absolute;\n    left: 4px; top: 11px;\n    width: 4px; height: 4px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n  }\n\n  /* ============ SECTION 6 — How It Works (SS3 style, dark) ============ */\n  .how{\n    position:relative;\n    padding: clamp(80px, 10vw, 130px) 0;\n    background: linear-gradient(135deg, #0E1116 0%, #161A22 100%);\n    color:#fff;\n    overflow:hidden;\n  }\n  .how::before{\n    content:\"\";\n    position:absolute;\n    top:-30%; left:-10%;\n    width:50%; height:80%;\n    background: radial-gradient(60% 60% at 50% 50%, rgba(87,109,181,.18), transparent 70%);\n    pointer-events:none;\n  }\n  .how::after{\n    content:\"\";\n    position:absolute;\n    bottom:-30%; right:-10%;\n    width:50%; height:80%;\n    background: radial-gradient(60% 60% at 50% 50%, rgba(143,188,143,.10), transparent 70%);\n    pointer-events:none;\n  }\n  .how-head{ position:relative; z-index:1; margin-bottom: 64px; }\n  .how-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    color: rgba(255,255,255,.6);\n    font-size: 11px; font-weight: 700;\n    letter-spacing: .24em; text-transform: uppercase;\n    margin-bottom: 16px;\n  }\n  .how-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--warm);\n  }\n  .how h2{\n    font-size: clamp(34px, 4.6vw, 60px);\n    line-height: 1.04;\n    letter-spacing: -.025em;\n    color: #fff;\n    font-weight: 700;\n    margin: 0;\n    text-wrap: balance;\n    max-width: 18ch;\n  }\n  .how-sub{\n    margin: 14px 0 0;\n    font-size: 16px;\n    line-height: 1.65;\n    color: rgba(255,255,255,.65);\n    max-width: 56ch;\n  }\n  .how-grid{\n    position:relative; z-index:1;\n    display:grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 0;\n  }\n  .how-step{\n    position:relative;\n    padding: 28px 28px;\n    border-left: 1px solid rgba(199,116,235,.30);\n    min-height: 280px;\n  }\n  .how-step:first-child{ border-left: none; padding-left: 0; }\n  .how-step .step-num{\n    position:absolute;\n    top: 0; right: 12px;\n    font-size: clamp(90px, 10vw, 150px);\n    font-weight: 800;\n    color: rgba(255,255,255,.04);\n    -webkit-text-stroke: 1px rgba(255,255,255,.10);\n    line-height: 0.9;\n    letter-spacing: -.05em;\n    z-index: 0;\n    pointer-events: none;\n  }\n  .how-step h3{\n    font-size: 20px; font-weight: 700;\n    color: #fff;\n    margin: 0 0 90px;\n    position: relative; z-index: 1;\n    letter-spacing: -.01em;\n  }\n  .how-step p{\n    font-size: 14.5px; line-height: 1.65;\n    color: rgba(255,255,255,.65);\n    margin: 0;\n    position: relative; z-index: 1;\n  }\n  .how-cta{\n    position:relative; z-index:1;\n    margin-top: 56px;\n    display:flex; gap: 14px; flex-wrap:wrap;\n  }\n  .how-btn{\n    padding: 14px 26px;\n    border-radius: 999px;\n    font-size: 14px; font-weight: 700;\n    transition: transform .15s, background .2s, border-color .2s;\n  }\n  .how-btn.primary{\n    background: var(--cta); color: #fff;\n    border: 1px solid var(--cta);\n  }\n  .how-btn.primary:hover{ background: var(--cta-hover); transform: translateY(-1px); }\n  .how-btn.ghost{\n    background: transparent; color: #fff;\n    border: 1px solid rgba(255,255,255,.4);\n  }\n  .how-btn.ghost:hover{ border-color: #fff; background: rgba(255,255,255,.06); transform: translateY(-1px); }\n\n  /* ============ FOOTER (matched to existing) ============ */\n  .footer{\n    background: var(--bg-alt);\n    color: var(--body);\n    padding: clamp(60px, 8vw, 90px) 0 32px;\n    border-top: 1px solid var(--line-soft);\n  }\n  .ft-grid{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr 1fr 1.4fr;\n    gap: clamp(28px, 4vw, 52px);\n    margin-bottom: 56px;\n  }\n  .ft-brand .ft-logo{\n    display:flex; align-items:center; height:38px; margin-bottom:18px;\n    font-size:18px; font-weight:800; color:var(--heading); letter-spacing:-.01em;\n  }\n  .ft-brand .ft-logo .logo-mark{ margin-right:10px; }\n  .ft-desc{ font-size:14px; line-height:1.65; color:var(--body); max-width: 32ch; margin: 0 0 22px; }\n  .ft-social{ display:flex; gap:10px; }\n  .ft-social a{\n    width:36px; height:36px;\n    border-radius:50%;\n    background: #fff;\n    border:1px solid var(--line-soft);\n    display:grid; place-items:center;\n    color: var(--body);\n    transition: color .2s, border-color .2s, transform .15s;\n  }\n  .ft-social a:hover{ color: var(--heading); border-color: var(--line); transform: translateY(-1px); }\n  .ft-h{\n    font-size: 12px; font-weight: 700; color: var(--heading);\n    letter-spacing: .12em; text-transform: uppercase;\n    margin: 0 0 18px;\n  }\n  .ft-list{ list-style:none; padding:0; margin:0; }\n  .ft-list li{ margin-bottom: 10px; }\n  .ft-list a{\n    font-size: 14px; color: var(--body);\n    transition: color .2s;\n  }\n  .ft-list a:hover{ color: var(--heading); }\n  .ft-text-link{ line-height: 1.5; }\n  .ft-news{ margin-top: 24px; }\n  .ft-news-h{ font-size: 13px; font-weight: 700; color: var(--heading); margin: 0 0 4px; }\n  .ft-news-p{ font-size: 13px; color: var(--muted); margin: 0 0 14px; line-height: 1.5; }\n  .ft-form{\n    display:flex;\n    border: 1px solid var(--line-soft);\n    border-radius: 10px;\n    overflow: hidden;\n    background: #fff;\n  }\n  .ft-form input{\n    flex: 1; min-width: 0;\n    padding: 11px 14px;\n    border: 0;\n    font-family: var(--font);\n    font-size: 13.5px;\n    color: var(--heading);\n    background: transparent;\n    outline: none;\n  }\n  .ft-form button{\n    background: var(--cta); color: #fff;\n    padding: 0 16px;\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 13px; font-weight: 600;\n    transition: background .2s;\n  }\n  .ft-form button:hover{ background: var(--cta-hover); }\n  .ft-bottom{\n    border-top: 1px solid var(--line-faint);\n    padding-top: 24px;\n    display:flex; align-items:center; justify-content:space-between;\n    flex-wrap: wrap; gap: 16px;\n  }\n  .ft-bottom span{ font-size: 13px; color: var(--muted); }\n  .ft-bottom-links{ display:flex; gap: 22px; flex-wrap: wrap; }\n  .ft-bottom-links a{\n    font-size: 13px; color: var(--muted);\n    transition: color .2s;\n  }\n  .ft-bottom-links a:hover{ color: var(--heading); }\n\n  /* ============ RESPONSIVE ============ */\n  @media (max-width: 1024px){\n    .menu, .nav-right .lang{ display:none; }\n    .hero-grid{ grid-template-columns: 1fr; gap: 48px; }\n    .hero-visual{ height: 460px; }\n    .what-grid{ grid-template-columns: 1fr; }\n    .impact-banner{ grid-template-columns: 1fr; }\n    .impact-visual{ aspect-ratio: 1.4; max-width: 480px; margin: 0 auto; }\n    .templates-head{ grid-template-columns: 1fr; gap: 24px; }\n    .templates-head .right{ text-align: left; margin: 0; }\n    .sol-head{ grid-template-columns: 1fr; gap: 18px; align-items: start; }\n    .sol-sub{ text-align: left; max-width: 56ch; margin: 0; }\n    .sol-grid{ grid-template-columns: repeat(2, 1fr); }\n    .sol-card{ min-height: 200px; }\n    .tpl-card{ flex: 0 0 100%; }\n    .tpl-desc{ font-size: 17px; }\n    .uc-grid{ grid-template-columns: 1fr; gap: 56px; }\n    .uc-visual{ max-width: 360px; }\n    .how-grid{ grid-template-columns: repeat(2, 1fr); gap: 0 24px; }\n    .how-step{ padding: 32px 0 32px 24px; min-height: 0; }\n    .how-step:nth-child(odd){ border-left: none; padding-left: 0; }\n    .how-step:nth-child(n+3){ border-top: 1px solid rgba(199,116,235,.20); padding-top: 32px; margin-top: 8px; }\n    .how-step h3{ margin-bottom: 16px; }\n    .how-step .step-num{ font-size: 110px; top: -10px; right: 0; }\n    .ft-grid{ grid-template-columns: 1fr 1fr; }\n    .ft-brand{ grid-column: 1 / -1; }\n  }\n\n  @media (max-width: 640px){\n    h1.title{ font-size: 36px; }\n    .hero-visual{ height: 380px; }\n    .h-main{ width: 80%; left: 0; }\n    .h-notif{ width: 65%; }\n    .h-integ{ width: 70%; }\n    .impact-stats{ grid-template-columns: 1fr; gap: 18px; }\n    .impact-stat::before{ display:none; }\n    .tpl-card{ flex: 0 0 100%; }\n    .slider-progress{ flex: 0 1 180px; }\n    .sol-grid{ grid-template-columns: 1fr; }\n    .uc-visual{ max-width: 280px; }\n    .how-grid{ grid-template-columns: 1fr; }\n    .how-step:nth-child(n){ border-left: none; padding-left: 0; padding-top: 32px; margin-top: 0; }\n    .how-step:first-child{ padding-top: 0; }\n    .how-step:nth-child(n+2){ border-top: 1px solid rgba(199,116,235,.20); }\n    .templates-foot{ flex-direction: column; align-items: flex-start; }\n    .ft-grid{ grid-template-columns: 1fr; }\n    .ft-bottom{ flex-direction: column; align-items: flex-start; }\n  }";
